<template>
  <div class="carousel fc card" :style="`width:${baseWidth * size}px;`">
    <div class="fr fac carousel-title">
      <h2>{{title}}</h2>
      <div class="fr fac">
        <i class="material-icons btn" :class="{'unavailable': index == 0}" @click="changeIndex(index - size)">keyboard_arrow_left</i>
        <span>{{index + 1}} of {{projects.length}}</span>
        <i class="material-icons btn" :class="{'unavailable': indexAtEnd(index + 1)}" @click="changeIndex(index + size)">keyboard_arrow_right</i>
      </div>
    </div>
    <div class="carousel-content fr" :style="`margin-left:${index * -baseWidth}px;`">
      <project class="carousel-item border-col2" :style="`width:${baseWidth}px;min-width:${baseWidth}px;`" v-for="repo in projects" :project="repo" :key="repo.name" />
    </div>
  </div>
</template>
<script>
import Project from './Project.vue'
export default {
  props: {
    title: String,
    size: Number,
    baseWidth: Number,
    projects: Array
  },
  components: {
    Project
  },
  data () {
    return {
      index: 0
    }
  },
  methods: {
    changeIndex (newIndex) {
      var l = this.projects.length
      if (newIndex < 0) newIndex = 0
      else if (newIndex >= l) return
      else if (this.indexAtEnd(newIndex)) newIndex -= 1
      this.index = newIndex
    },
    indexAtEnd (index) {
      var l = this.projects.length
      return index + this.size > l
    }
  }
}
</script>
<style lang="scss">
.carousel {
  display: inline-block;
  overflow:hidden;
  h2 {
    flex: 1;
    padding-top: 5px;
    text-align: left;
  }
  .carousel-title {
    border-bottom: 1px solid #0004;
    padding-left: 10px;
    padding-right: 2px;
  }
  height: auto !important;
}
.carousel-content {
  overflow:clip !important;
  padding: 10px 0px;
  transition: margin-left 0.5s;
}
.carousel-item {
  border-right-style: solid;
  border-width: 1px;
}
</style>
