<template>
  <div class="fc app-container fjc">
    <div id="nav" class="fr fac fjc fw">
      <div style="width:100px"></div>
      <h1>Tadeas Paule</h1>
      <div class="fc navlinks">
        <router-link to="/" v-slot="{ href, navigate, isActive }">
          <a :class="{'active': isActive} " :href="href" @click="navigate">Projects</a>
        </router-link>
        <router-link to="/experience" v-slot="{ href, navigate, isActive }">
          <a :class="{'active': isActive} " :href="href" @click="navigate">Experience</a>
        </router-link>
        <router-link to="/education" v-slot="{ href, navigate, isActive }">
          <a :class="{'active': isActive} " :href="href" @click="navigate">Education</a>
        </router-link>
      </div>
    </div>
    <router-view v-bind="{topics: projectTopics, allRepos: allRepos}"/>
  </div>
</template>
<script>
import axios from 'axios'
export default {
  data () {
    return {
      allRepos: [],
      projects: {
        ai: ['ai-demos', 'snake-neuroevolution', 'generalised-rl-environment', 'universal-name-generator'],
        gamedev: ['puzzling-remarks', 'unity-isometric-map-generation', 'ld47-prison-of-time', 'ld46-babysitter', 'mj42-slay-the-summer', 'mj41-wizard-snake', 'ld45-the-jam-ends-in-1-second'],
        art: ['gallery', 'wallpapers', 'generate-drip-paintings', 'twitchy-processing-mess'],
        other: ['twsr', 'ebookjs']
      },
      extraLinks: {
        // ebookjs: [{ name: 'npm', link: 'https://www.npmjs.com/package/ebookjs' }] -> npm link now on github,
        // system can still be used later for something with for ex 2 extra links, one on github one here
      }
    }
  },
  mounted () {
    axios.get('https://api.github.com/users/tadeaspaule/repos', { headers: { Accept: 'application/vnd.github.mercy-preview+json' } }).then(r => {
      this.allRepos = r.data
    })
  },
  computed: {
    repoMap () {
      var map = {}
      this.allRepos.forEach(r => { map[r.name] = r })
      return map
    },
    projectTopics () {
      return Object.keys(this.projects).map(p => {
        return {
          name: p,
          size: this.getTopicSize(p),
          repos: this.getRepoData(p)
        }
      })
    }
  },
  methods: {
    getRepoData (name) {
      if (this.allRepos.length === 0 || Object.keys(this.repoMap) === 0) return []
      console.log(this.repoMap)
      return this.projects[name].filter(n => this.repoMap[n]).map(n => {
        var repo = this.repoMap[n]
        repo.extraLinks = []
        if (this.extraLinks[n]) repo.extraLinks = this.extraLinks[n]
        if (repo.homepage && (!this.extraLinks[n] || !this.extraLinks[n].find(el => el.link === repo.homepage))) {
          Array.prototype.push.apply(repo.extraLinks, [{ name: this.getLinkName(repo.homepage), link: repo.homepage }])
        }
        return repo
      })
    },
    getLinkName (link) {
      if (link.match(/tadeaspaule.itch.io/)) return 'itch'
      if (link.match(/npmjs.com\/package\//)) return 'npm'
      return 'web'
    },
    getTopicSize (topic) {
      if ((topic === 'ai' || topic === 'gamedev') && window.innerWidth > 850) return 2
      return 1
    }
  }
}
</script>
