<template>
  <div class="projects fc" :style="`width:${width * maxSize}px`">
    <div class="fr fw">
      <project-topic v-for="topic in topics" :key="topic.name" :style="`margin:${margin}px;`"
        :topic="topic" :size="topic.size" :width="width * topic.size" :baseWidth="width - margin - (maxSize - topic.size) * margin"/>
    </div>
    <!-- <a href="https://github.com/tadeaspaule?tab=repositories" target="_blank">{{allRepos.length - shownRepos}} more on Github</a> -->
  </div>
</template>

<script>
import ProjectTopic from '../components/ProjectTopic.vue'
export default {
  name: 'Home',
  components: {
    ProjectTopic
  },
  props: {
    topics: Object,
    allRepos: Array
  },
  data () {
    return {
      width: 400,
      margin: 5
    }
  },
  computed: {
    maxSize () {
      if (window.innerWidth > (this.width + this.margin) * 2) return 2
      return 1
    },
    shownRepos () {
      return Object.keys(this.topics).map(t => this.topics[t].repos.length).reduce((a, b) => a + b)
    }
  }
}
</script>
<style lang="scss">
.projects {
  overflow:hidden;
  margin-left: auto;
  margin-right: auto;
}
</style>
